function firstName(name) {
  return String(name || 'cliente').trim().split(/\s+/)[0] || 'cliente';
}
const data = $json;
const nome = firstName(data.customer_name);
const reply = 'Olá, ' + nome + '. Vou encaminhar seu atendimento para nossa equipe humana dar sequência e te responder por aqui.';
return [{ json: { ...data, reply_text: reply, reply_subject: 'Transferencia para atendimento humano', event_type: 'automation.trigger', entity_type: 'leads_contabilidade' } }];
